use std::str::FromStr;

#[derive(Debug, PartialEq)]
struct Coordinate {
    file: char,
    rank: u8,
}

impl FromStr for Coordinate {
    type Err = String;

    fn from_str(s: &str) -> Result<Self, Self::Err> {
        if s.len() != 2 {
            return Err(format!("Invalid length for coordinate: {}", s));
        }
        let file = s.chars().next().unwrap();
        let rank_char = s.chars().nth(1).unwrap();
        if !rank_char.is_ascii_digit() {
            return Err(format!("Rank must be a digit: {}", s));
        }
        let rank = u8::from_str(&rank_char.to_string()).map_err(|_| format!("Failed to parse rank digit from: {}", s))?;
        Ok(Coordinate { file, rank })
    }
}

fn main() {
    let input_string = "a1 b3 c5";
    let parts: Vec<&str> = input_string.split_whitespace().collect();

    let mut parsed_coords: Vec<Coordinate> = Vec::new();
    for part in parts {
        match Coordinate::from_str(part) {
            Ok(coord) => {
                println!("Successfully parsed coordinate: {:?}", coord);
                parsed_coords.push(coord);
            },
            Err(e) => {
                println!("Skipping part due to error: {}", e);
            }
        }
    }

    println!("nAll parsed coordinates: {:?}", parsed_coords);
}

use std::str::FromStr;

#[derive(Debug, Clone, PartialEq)]
struct BuildTarget {
    name: String,
    output_path: String,
    is_cached: bool,
}
impl FromStr for BuildTarget {
    type Err = String;
    fn from_str(s: &str) -> Result<Self, Self::Err> {
        let parts: Vec<&str> = s.split(':').collect();
        if parts.len() != 3 {
            return Err(format!("Invalid format. Expected 'name:path:bool', got '{}'", s));
        }

        let name = parts[0].to_string();
        let output_path = parts[1].to_string();
        let is_cached = parts[2].trim() == "true";

        Ok(BuildTarget {
            name,
            output_path,
            is_cached,
        })
    }
}

fn main() {
    let config_line1 = "main_app:./build/main.o:true";
    let config_line2 = "utility:./build/util.o:false";
    let invalid_line = "missing_parts";

    match BuildTarget::from_str(config_line1) {
        Ok(target) => println!("Successfully parsed target 1: {:?}", target),
        Err(e) => eprintln!("Error parsing target 1: {}", e),
    }

    match BuildTarget::from_str(config_line2) {
        Ok(target) => println!("Successfully parsed target 2: {:?}", target),
        Err(e) => eprintln!("Error parsing target 2: {}", e),
    }

    match BuildTarget::from_str(invalid_line) {
        Ok(target) => println!("Unexpected success for invalid line: {:?}", target),
        Err(e) => println!("Correctly caught error for invalid line: {}", e),
    }
}

use std::str::FromStr;

#[derive(Debug, PartialEq)]
struct MemoryAddress(u64);
impl FromStr for MemoryAddress {
    type Err = String;
    fn from_str(s: &str) -> Result<Self, Self::Err> {
        match u64::from_str(s) {
            Ok(val) => Ok(MemoryAddress(val)),
            Err(_) => Err(format!("Invalid address format provided for memory pointer."))
        }
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let valid_input = "0x7f8c12345678";
    let invalid_input = "not a number";

    let address1: MemoryAddress = match MemoryAddress::from_str(valid_input) {
        Ok(addr) => addr,
        Err(e) => { 
            println!("Failed to parse valid input: {}", e);
            return Ok(()) as Result<(), Box<dyn std::error::Error>>;
        }
    };

    println!("Successfully parsed address: {:?}", address1);

    let result2 = MemoryAddress::from_str(invalid_input);
    match result2 {
        Ok(_) => println!("Unexpectedly succeeded parsing invalid input."),
        Err(e) => println!("Correctly failed to parse: {}", e),
    }

    Ok(())
}

use std::str::FromStr;
use std::fmt::{self, Display};

#[derive(Debug, PartialEq)]
struct LogEntry {
    timestamp: String,
    level: String,
    message: String,
}

impl FromStr for LogEntry {
    type Err = String;

    fn from_str(s: &str) -> Result<Self, Self::Err> {
        let parts: Vec<&str> = s.trim().split("|").collect();
        if parts.len() != 3 {
            return Err(format!("Invalid log format: expected 3 pipe-separated fields, got {}", parts.len()));
        }
        Ok(LogEntry {
            timestamp: parts[0].to_string(),
            level: parts[1].to_string(),
            message: parts[2].to_string().replace("n", ""),
        })
    }
}

impl Display for LogEntry {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "[{}] {} - {}", self.timestamp, self.level, self.message)
    }
}

fn main() {
    let log_line = "2023-10-27T10:00:00|ERROR|Database connection timed out";
    match LogEntry::from_str(log_line) {
        Ok(entry) => println!("Successfully parsed entry: {}", entry),
        Err(e) => eprintln!("Failed to parse log line: {}", e),
    }

    let bad_line = "2023-10-27T10:00:00|INFO";
    match LogEntry::from_str(bad_line) {
        Ok(_) => println!("Should not happen."),
        Err(e) => println!("Correctly failed to parse bad line: {}", e),
    }
}
